import{_ as e,o as a,c as r,ak as l}from"./chunks/framework.CY1a07lP.js";const f=JSON.parse('{"title":"关于大熊猫服务器","description":"","frontmatter":{},"headers":[],"relativePath":"other/about.md","filePath":"other/about.md","lastUpdated":1777866000000}'),o={name:"other/about.md"};function s(n,t,d,i,g,h){return a(),r("div",null,[...t[0]||(t[0]=[l('<h1 id="关于大熊猫服务器" tabindex="-1">关于大熊猫服务器 <a class="header-anchor" href="#关于大熊猫服务器" aria-label="Permalink to “关于大熊猫服务器”">​</a></h1><p>这是一个始于2019年9月的老牌服务器。自Minecraft 1.14版本开服，历经数个版本周期与周目，始终由服主一人独立管理、更新与维护，坚持运营至今。</p><p>由于服务器运营需要承担电费、网费等基础开销，无法长期维持公益模式，自1.14版本后已全面转为商业服务器。我们坚持使用正版插件以确保稳定与安全，并注重售后维护。<strong>虽然转为商业运营，但游戏内充值玩家与非充值玩家之间的差距很小，不会因赞助而偏袒任何玩家，全力保障所有玩家的公平游戏体验。</strong></p><p><strong>本服正朝轻RPG与多元化玩法发展，定位为插件服，而非纯粹的生电服。</strong> 在不完全禁止生电行为的前提下会进行适当限制，属于半生电服。通过拓展更多游戏内容，旨在延长服务器生命周期，为玩家提供持久而丰富的体验。</p><h1 id="赞助服务器" tabindex="-1">赞助服务器 <a class="header-anchor" href="#赞助服务器" aria-label="Permalink to “赞助服务器”">​</a></h1><p><strong>赞助是获得不影响游戏平衡的游戏权限的重要途径</strong>，主要包括三种方式：直接购买点券、购买月卡（减负包）以及参与众筹。</p><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">主要用途与特点</th><th style="text-align:left;">核心奖励与权益</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>点券</strong></td><td style="text-align:left;">用于购买权限的主要代币。</td><td style="text-align:left;">- 可兑换游戏币、彩色聊天字体、更多附魔查询、称号装饰、增加上架物品数量等功能性或装饰性权限。<br>- 有效期通常为一个月。</td></tr><tr><td style="text-align:left;"><strong>月卡</strong><br>(减负包)</td><td style="text-align:left;">按月订阅服务，提供持续的游戏内收益与福利。</td><td style="text-align:left;">- <strong>购买即得</strong>：200点券。<br>- <strong>每日领取</strong>：800游戏币 + 1个不死图腾。<br>- <strong>持续特权</strong>：圈地价格降低0.1、领地上限+1、mcmmo经验获取+10%。</td></tr><tr><td style="text-align:left;"><strong>众筹</strong></td><td style="text-align:left;">多人共同赞助以添加新插件，侧重于娱乐与便利。</td><td style="text-align:left;">- 加入众筹组，获得额外领地及设家上限。<br>- 解锁部分娱乐/功能插件权限（如CMI的<code>/ride</code>、<code>/hat</code>、盔甲架编辑等），不影响游戏平衡。</td></tr></tbody></table><p>前两种可以在游戏中输入<code>/菜单</code>后，于界面右下角点击赞助菜单进入相关界面。 :::</p><h1 id="贡献" tabindex="-1">贡献 <a class="header-anchor" href="#贡献" aria-label="Permalink to “贡献”">​</a></h1><p>本文档欢迎贡献！如有建议或错误，请：</p><ul><li><a href="https://github.com/Redersha/panda_server_guide_v2/issues" target="_blank" rel="noreferrer">提交Issues</a></li><li>附上markdown文件</li><li>或联系q群 <code>@再也不剪宣传片了</code> :::</li></ul>',11)])])}const p=e(o,[["render",s]]);export{f as __pageData,p as default};
